```class Solution {
    public int minimumChanges(String s, int k) {
        int result = 0;
        int[] count = new int[26];
        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']++;
        }
        for (int i = 0; i < k; i++) {
            for (int j = 0; j < s.length(); j++) {
                if (count[s.charAt(j) - 'a'] == 0) {
                    result += 1;
                }
            }
        }
        return result;
    }
}
